import React, { forwardRef } from "react";

/**
 * Shared prop contract — mirrors lucide-react's API:
 *  - `size` sets width/height directly (number = px, string = any CSS unit)
 *  - omit `size` and the icon defaults to `1em`, so font-size utilities
 *    like `text-2xl` resize it automatically (set on a wrapping element
 *    or directly on the icon via className if you prefer Tailwind's
 *    `size-*` utilities instead).
 *  - `className` / `style` / any other svg attr passes straight through.
 *
 * Color note: monochrome icons (Next.js, GSAP) use `fill="currentColor"`,
 * so `text-*` color utilities or a `color` style change them like any
 * lucide icon. The others (Flutter, Figma, Dart, TypeScript, Tailwind CSS,
 * Zod, PHP) are official multi-color brand marks — their fills are fixed
 * to the brand palette by design and won't respond to `currentColor`.
 */
export interface IconProps extends React.SVGProps<SVGSVGElement> {
  size?: number | string;
}

function buildTitleProps(title?: string) {
  return title
    ? { role: "img" as const, "aria-label": title }
    : { "aria-hidden": true as const, focusable: false as const };
}

